  contract.landing_pad_sites = 0;
  contract.cleanup_resume_sites =
      std::min(raw_resume_sites, contract.unwind_cleanup_sites);
  contract.normalized_sites =
      std::min(raw_normalized_sites, contract.unwind_cleanup_sites);
